import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';
import 'package:collection/collection.dart';
import 'package:flutter/material.dart';
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

enum AICoachPromotionStyle {
  simpleBorder,
  gradient,
  card,
  outlined,
  shadowed,
  neon,
  minimal,
  badge,
  ribbon,
  glossy,
}

class AICoachPromotionContainer extends ConsumerWidget {
  const AICoachPromotionContainer._({
    required this.style,
    super.key,
  });

  factory AICoachPromotionContainer.simpleBorder({Key? key}) {
    return AICoachPromotionContainer._(
      style: AICoachPromotionStyle.simpleBorder,
      key: key,
    );
  }

  factory AICoachPromotionContainer.gradient({Key? key}) {
    return AICoachPromotionContainer._(
      style: AICoachPromotionStyle.gradient,
      key: key,
    );
  }

  factory AICoachPromotionContainer.card({Key? key}) {
    return AICoachPromotionContainer._(
      style: AICoachPromotionStyle.card,
      key: key,
    );
  }

  factory AICoachPromotionContainer.outlined({Key? key}) {
    return AICoachPromotionContainer._(
      style: AICoachPromotionStyle.outlined,
      key: key,
    );
  }

  factory AICoachPromotionContainer.shadowed({Key? key}) {
    return AICoachPromotionContainer._(
      style: AICoachPromotionStyle.shadowed,
      key: key,
    );
  }

  factory AICoachPromotionContainer.neon({Key? key}) {
    return AICoachPromotionContainer._(
      style: AICoachPromotionStyle.neon,
      key: key,
    );
  }

  factory AICoachPromotionContainer.minimal({Key? key}) {
    return AICoachPromotionContainer._(
      style: AICoachPromotionStyle.minimal,
      key: key,
    );
  }

  factory AICoachPromotionContainer.badge({Key? key}) {
    return AICoachPromotionContainer._(
      style: AICoachPromotionStyle.badge,
      key: key,
    );
  }

  factory AICoachPromotionContainer.ribbon({Key? key}) {
    return AICoachPromotionContainer._(
      style: AICoachPromotionStyle.ribbon,
      key: key,
    );
  }

  factory AICoachPromotionContainer.glossy({Key? key}) {
    return AICoachPromotionContainer._(
      style: AICoachPromotionStyle.glossy,
      key: key,
    );
  }

  final AICoachPromotionStyle style;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final teamList = ref.watch(teamListControllerProvider);
    return teamList.when(
      error: (Object error, StackTrace stackTrace) => const SizedBox.shrink(),
      loading: () => const SizedBox.shrink(),
      data: (teams) {
        if (teams.hasLeft) return const SizedBox.shrink();
        final teamId = ref.read(profileStorageProvider).getTeamId();
        final team = teams.right.firstWhereOrNull((t) => t.id == teamId);
        if (team != null &&
            team.isSingleUserTeam == true &&
            team.teamPlan?.isInAppleSubscription != true &&
            team.teamPlan?.isInStripeSubscription != true) {
          return _buildStyleContainer();
        } else {
          return const SizedBox.shrink();
        }
      },
    );
  }

  Widget _buildStyleContainer() {
    switch (style) {
      case AICoachPromotionStyle.simpleBorder:
        return _SimpleBorderStyle();
      case AICoachPromotionStyle.gradient:
        return _GradientStyle();
      case AICoachPromotionStyle.card:
        return _CardStyle();
      case AICoachPromotionStyle.outlined:
        return _OutlinedStyle();
      case AICoachPromotionStyle.shadowed:
        return _ShadowedStyle();
      case AICoachPromotionStyle.neon:
        return _NeonStyle();
      case AICoachPromotionStyle.minimal:
        return _MinimalStyle();
      case AICoachPromotionStyle.badge:
        return _BadgeStyle();
      case AICoachPromotionStyle.ribbon:
        return _RibbonStyle();
      case AICoachPromotionStyle.glossy:
        return _GlossyStyle();
    }
  }
}

